const headers = items[0].json.headers || {};
const body = items[0].json.body || {};

const ua = headers['user-agent'] || "N/A";

let risk = "BAJO";

if (/sqlmap|nmap|nikto|dirbuster|wpscan/i.test(ua)) {
  risk = "CRITICO";
}

return {
  ip: headers['x-forwarded-for'] || headers['x-real-ip'] || "unknown",
  method: items[0].json.method,
  path: items[0].json.url,
  user_agent: ua,
  body: JSON.stringify(body),
  severity: risk,
  timestamp: new Date().toISOString()
};

const fs = require('fs');
const path = require('path');

const logPath = '/home/node/scripts/honeytrap.log';

const data = items[0].json;

const logLine = [
  '============================================================',
  `[${data.timestamp}] INCIDENTE CRITICO DETECTADO`,
  `IP Origen     : ${data.ip}`,
  `Metodo HTTP   : ${data.method}`,
  `Ruta accedida : ${data.path}`,
  `User-Agent    : ${data.user_agent}`,
  `Severidad     : ${data.severity}`,
  `Body          : ${data.body}`,
  `Acciones      : Telegram notificado | MailHog enviado | Registro en PostgreSQL`,
  '============================================================'
].join('\n') + '\n\n';

try {
  fs.appendFileSync(logPath, logLine, 'utf8');
} catch (e) {
  fs.mkdirSync(path.dirname(logPath), { recursive: true });
  fs.appendFileSync(logPath, logLine, 'utf8');
}

return {
  log_path: logPath,
  log_entry: logLine,
  status: 'Log escrito correctamente'
};
